mapper.select:
SELECT id, title, summary, category, tag, tag_type, cover_icon, cover_color, status, view_count, like_count, is_top, sort, create_time, update_time FROM blog_article
AND category LIKE CONCAT('%', #{category}, '%')
AND status = #{status}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR summary LIKE CONCAT('%', #{keyword}, '%'))
AND is_top = #{isTop}
ORDER BY is_top DESC, sort DESC, create_time DESC

mapper.update:
UPDATE blog_article
title = #{title}, summary = #{summary}, content_md = #{contentMd}, content_html = #{contentHtml}, category = #{category}, tag = #{tag}, tag_type = #{tagType}, cover_icon = #{coverIcon}, cover_color = #{coverColor}, status = #{status}, is_top = #{isTop}, sort = #{sort}, update_time = NOW()
WHERE id = #{id}
